### Reusable Code Snippets:

```cpp
// Example state transition validation logic (to be implemented in IsValidTransition)
bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const
{
    switch (from) {
        case kDeviceStateUnknown:
            return to == kDeviceStateStarting;

        case kDeviceStateStarting:
            return to == kDeviceStateWifiConfiguring || to == kDeviceStateIdle || to == kDeviceStateFatalError;

        case kDeviceStateWifiConfiguring:
            return to == kDeviceStateIdle || to == kDeviceStateFatalError;

        case kDeviceStateIdle:
            return to == kDeviceStateConnecting || to == kDeviceStateListening || 
                   to == kDeviceStateAudioTesting || to == kDeviceStateUpgrading ||
                   to == kDeviceStateActivating || to == kDeviceStateFatalError;

        case kDeviceStateConnecting:
            return to == kDeviceStateListening || to == kDeviceStateIdle || to == kDeviceStateFatalError;

        case kDeviceStateListening:
            return to == kDeviceStateSpeaking || to == kDeviceStateIdle || to == kDeviceStateFatalError;

        case kDeviceStateSpeaking:
            return to == kDeviceStateIdle || to == kDeviceStateListening || to == kDeviceStateFatalError;

        case kDeviceStateUpgrading:
            return to == kDeviceStateActivating || to == kDeviceStateFatalError;

        case kDeviceStateActivating:
            return to == kDeviceStateIdle || to == kDeviceStateFatalError;

        case kDeviceStateAudioTesting:
            return to == kDeviceStateIdle || to == kDeviceStateFatalError;

        case kDeviceStateFatalError:
            // Fatal error should not transition to any other state
            return false;

        default:
            return false;
    }
}
```

```cpp
// Helper method to get state name for logging
const char *DeviceStateMachine::GetStateName(DeviceState state)
{
    if (state >= 0 && state <= kDeviceStateFatalError) {
        return STATE_STRINGS[state];
    }
    return STATE_STRINGS[kDeviceStateFatalError + 1]; // "invalid_state"
}
```

```cpp
// Usage of IsValidTransition within TransitionTo
bool DeviceStateMachine::TransitionTo(DeviceState new_state)
{
    DeviceState old_state = current_state_.load();

    // No-op if already in the target state
    if (old_state == new_state) {
        return true;
    }

    // Validate transition
    if (!IsValidTransition(old_state, new_state)) {
        ESP_LOGW(TAG, "Invalid state transition: %s -> %s",
                 GetStateName(old_state), GetStateName(new_state));
        return false;
    }

    // Perform transition
    current_state_.store(new_state);
    ESP_LOGI(TAG, "State: %s -> %s",
             GetStateName(old_state), GetStateName(new_state));

    // Notify callback
    NotifyStateChange(old_state, new_state);
    return true;
}
```

### Key Insights:
- Transitions must follow a deterministic finite automaton model.
- Logging is important using `ESP_LOGW` for warnings and `ESP_LOGI` for info.
- Each state should only allow specific transitions based on business logic.
- The fatal error state typically blocks all further transitions.
- Use `std::atomic<>` (`current_state_.load()` / `.store()`) for thread-safe access to shared state variables.
- Observer pattern via `NotifyStateChange` allows decoupled reaction to state changes.

