This function uses `uxTaskGetSystemState()` to enumerate tasks — a core requirement for printing task lists as well.

```cpp
#define ARRAY_SIZE_OFFSET 5

void SystemInfo::PrintTaskList()
{
    TaskStatus_t *pxTaskStatusArray;
    volatile UBaseType_t uxArraySize, x;
    uint32_t ulTotalRunTime;

    // Take a snapshot of the number of tasks in case it changes while we are doing this
    uxArraySize = uxTaskGetNumberOfTasks() + ARRAY_SIZE_OFFSET;

    // Allocate an array index for each task
    pxTaskStatusArray = (TaskStatus_t *)malloc(uxArraySize * sizeof(TaskStatus_t));

    if (pxTaskStatusArray != NULL)
    {
        // Generate raw status information about each task
        uxArraySize = uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, &ulTotalRunTime);

        // Print header
        printf("Task List:\\n");
        printf("| Task Name       | Status | Prio | Stack High Water Mark | Task Number | Core ID |\\n");

        // For each populated position in the pxTaskStatusArray array,
        // output the task's name, state, priority, and stack high water mark.
        for (x = 0; x < uxArraySize; x++)
        {
            const char* state_str = "Unknown";
            switch (pxTaskStatusArray[x].eCurrentState)
            {
                case eRunning:   state_str = "Running";   break;
                case eReady:     state_str = "Ready";     break;
                case eBlocked:   state_str = "Blocked";   break;
                case eSuspended: state_str = "Suspended"; break;
                case eDeleted:   state_str = "Deleted";   break;
                default:         state_str = "Invalid";   break;
            }

            printf("| %-15s | %-7s| %4u | %9u             | %10u  | %7d |\\n",
                   pxTaskStatusArray[x].pcTaskName,
                   state_str,
                   pxTaskStatusArray[x].uxCurrentPriority,
                   pxTaskStatusArray[x].usStackHighWaterMark,
                   pxTaskStatusArray[x].xTaskNumber,
                   pxTaskStatusArray[x].xCoreID);
        }

        free(pxTaskStatusArray);
    }
    else
    {
        ESP_LOGE(TAG, "Failed to allocate memory for task list");
    }
}
```

