void AfeWakeWord::AudioDetectionTask()
{
    ESP_LOGI(TAG, "Audio detection task started");

    while (true) {
        xEventGroupWaitBits(event_group_, DETECTION_RUNNING_EVENT, pdFALSE, pdTRUE, portMAX_DELAY);

        auto res = afe_iface_->fetch_with_delay(afe_data_, portMAX_DELAY);
        if ((xEventGroupGetBits(event_group_) & DETECTION_RUNNING_EVENT) == 0) {
            continue;
        }

        if (res == nullptr || res->ret_value == ESP_FAIL) {
            continue;
        }

        // Handle wake word detection result
        if (res->wakeup_word_id > 0) {
            StoreWakeWordData(res->data, res->data_size / sizeof(int16_t));

            if (wake_word_detected_callback_) {
                // Get wake word string from ID
                std::string wake_word = wake_words_[res->wakeup_word_id - 1];
                wake_word_detected_callback_(wake_word);
            }

            EncodeWakeWordData();
        }
    }
}
```

