```cpp
void CustomWakeWord::ParseWakenetModelConfig()
{
    if (models_ == nullptr) {
        return;
    }

    // Clear existing commands
    commands_.clear();

    // Parse JSON configuration from model list
    cJSON *config = cJSON_Parse((char *)models_->model_list[0]);
    if (config == nullptr) {
        ESP_LOGE(TAG, "Failed to parse wakenet model config");
        return;
    }

    // Extract language
    cJSON *language = cJSON_GetObjectItem(config, "language");
    if (language && cJSON_IsString(language)) {
        language_ = language->valuestring;
    }

    // Extract duration
    cJSON *duration = cJSON_GetObjectItem(config, "duration");
    if (duration && cJSON_IsNumber(duration)) {
        duration_ = duration->valueint;
    }

    // Extract threshold
    cJSON *threshold = cJSON_GetObjectItem(config, "threshold");
    if (threshold && cJSON_IsNumber(threshold)) {
        threshold_ = (float)threshold->valuedouble;
    }

    // Extract commands
    cJSON *commands = cJSON_GetObjectItem(config, "commands");
    if (commands && cJSON_IsArray(commands)) {
        for (int i = 0; i < cJSON_GetArraySize(commands); i++) {
            cJSON *command_item = cJSON_GetArrayItem(commands, i);
            if (command_item) {
                Command cmd;
                cJSON *command = cJSON_GetObjectItem(command_item, "command");
                cJSON *text = cJSON_GetObjectItem(command_item, "text");
                cJSON *action = cJSON_GetObjectItem(command_item, "action");

                if (command && cJSON_IsString(command)) {
                    cmd.command = command->valuestring;
                }
                if (text && cJSON_IsString(text)) {
                    cmd.text = text->valuestring;
                }
                if (action && cJSON_IsString(action)) {
                    cmd.action = action->valuestring;
                }

                commands_.push_back(cmd);
            }
        }
    }

    cJSON_Delete(config);
}
```

This implementation follows the pattern seen in the system where:
1. Configuration is parsed from JSON format stored in model lists
2. Member variables are populated from the parsed configuration
3. Proper error handling and logging is included
4. Memory is properly managed (cJSON objects are deleted after use)

The function extracts the core configuration parameters needed for wake word detection: language, duration, threshold, and the list of commands with their associated actions and display text.

