```cpp
void CustomWakeWord::Feed(const std::vector<int16_t>& data)
{
    if (!running_ || multinet_model_data_ == nullptr || data.empty()) {
        return;
    }

    // Optionally store raw PCM data for encoding later (e.g., for upload)
    StoreWakeWordData(data);

    // Perform multinet detection on each chunk
    esp_mn_result_t result;
    multinet_->detect(multinet_model_data_, (int16_t*)data.data(), &result);

    if (result.wakenet_mode == MN_MODE_WAKEWORD && result.command_id >= 0) {
        // Wake word or command detected
        const std::string& detected_command = commands_[result.command_id - 1].text;
        last_detected_wake_word_ = detected_command;

        if (wake_word_detected_callback_) {
            wake_word_detected_callback_(detected_command);
        }

        // Trigger encoding of buffered audio upon detection
        EncodeWakeWordData();
    }
}
```

