```cpp
float FrequencyDetector::GetAmplitude() const
{
    if (state_buffer_.size() < 2) {
        return 0.0f;
    }

    // Get the last two states from the buffer
    auto it = state_buffer_.rbegin();
    float s_current = *it;
    ++it;
    float s_minus_1 = *it;

    // Calculate amplitude using Goertzel algorithm formula:
    // amplitude = sqrt(s[n]^2 + s[n-1]^2 - s[n] * s[n-1] * 2 * cos(ω))
    float real_part = s_current - s_minus_1 * cos_coefficient_;
    float imag_part = s_minus_1 * sin_coefficient_;
    float amplitude = std::sqrt(real_part * real_part + imag_part * imag_part);

    return amplitude;
}
```

This implementation follows the standard Goertzel algorithm where the amplitude is calculated from the final state values in the buffer, using the precomputed cosine and sine coefficients stored as member variables.

