std::vector<uint8_t> ConvertBitsToBytes(const std::vector<uint8_t>& bits) const {
    std::vector<uint8_t> bytes;
    size_t num_bits = bits.size();

    // Process every 8 bits as a byte
    for (size_t i = 0; i < num_bits; i += 8) {
        uint8_t byte = 0;
        size_t bits_to_process = std::min(static_cast<size_t>(8), num_bits - i);

        for (size_t j = 0; j < bits_to_process; ++j) {
            byte |= (bits[i + j] << (7 - j));
        }

        if (bits_to_process == 8) {
            bytes.push_back(byte);
        }
    }

    return bytes;
}
