#### 1. UUID Generation Using ESP32 Random Functions
The ESP32 provides a hardware random number generator which can be used to generate UUIDs. The `esp_random()` function returns a 32-bit random number that can be used to construct a UUID.

```cpp
#include <esp_random.h>
#include <sstream>
#include <iomanip>

std::string Board::GenerateUuid()
{
    uint32_t random1 = esp_random();
    uint32_t random2 = esp_random();
    uint32_t random3 = esp_random();
    uint32_t random4 = esp_random();

    std::stringstream ss;
    ss << std::hex << std::setfill('0');
    ss << std::setw(8) << (random1 & 0xFFFFFFFF) << "-";
    ss << std::setw(4) << (random2 >> 16) << "-";
    ss << std::setw(4) << (random2 & 0xFFFF) << "-";
    ss << std::setw(4) << (random3 >> 16) << "-";
    ss << std::setw(4) << (random3 & 0xFFFF) << std::setw(8) << (random4 & 0xFFFFFFFF);

    std::string uuid = ss.str();
    // Convert to lower case if required
    for (auto& c : uuid) {
        if (c >= 'A' && c <= 'F') {
            c += ('a' - 'A');
        }
    }

    return uuid;
}
```

#### 2. MAC Address-Based UUID (Alternative Method)
Another common method is to use the device's MAC address as part of the UUID to ensure uniqueness across devices.

```cpp
#include <esp_system.h>
#include <sstream>
#include <iomanip>

std::string Board::GenerateUuid()
{
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);

    std::stringstream ss;
    ss << std::hex << std::setfill('0');
    ss << "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx";

    // Replace x with hex digits from MAC and random numbers
    int mac_index = 0;
    std::string result = ss.str();
    for (char& c : result) {
        if (c == 'x') {
            uint8_t rand_byte = esp_random() & 0xFF;
            c = "0123456789abcdef"[rand_byte % 16];
        } else if (c == 'y') {
            // Set version 4 UUID bits
            c = "89ab"[esp_random() % 4];
        }
    }

    return result;
}
```

#### 3. Simple Hex String Based UUID Generator
A simple approach using only `esp_random()` without strict UUID formatting compliance but sufficient for most embedded applications.

```cpp
#include <esp_random.h>
#include <cstring>

std::string Board::GenerateUuid()
{
    char uuid[37]; // Format: xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx + null terminator
    const char* hex_chars = "0123456789abcdef";

    for (int i = 0; i < 36; ++i) {
        if (i == 8 || i == 13 || i == 18 || i == 23) {
            uuid[i] = '-';
        } else {
            uint8_t rand_val = esp_random() & 0xFF;
            uuid[i] = hex_chars[rand_val % 16];
        }
    }
    uuid[36] = '\0';

    return std::string(uuid);
}
```

These implementations provide different approaches to generating unique identifiers suitable for embedded systems like ESP32, balancing between true randomness, uniqueness guarantees, and computational efficiency.

