Periodic blinking is implemented using `esp_timer` with a callback that toggles LED state based on counter logic.
```cpp
void SingleLed::StartBlinkTask(int times, int interval_ms)
{
    if (led_strip_ == nullptr)
    {
        return;
    }

    std::lock_guard<std::mutex> lock(mutex_);
    esp_timer_stop(blink_timer_);

    blink_counter_ = times * 2;
    blink_interval_ms_ = interval_ms;

    esp_timer_create_args_t timer_args = {
        .callback = [](void* arg) {
            static_cast<SingleLed*>(arg)->OnBlinkTimer();
        },
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK,
        .name = "blink_timer"
    };

    esp_timer_create(&timer_args, &blink_timer_);
    esp_timer_start_periodic(blink_timer_, interval_ms * 1000);
}
```

