```cpp
// Example of how to structure an encrypted audio packet for sending
std::string MqttProtocol::EncryptAndSerializeAudioPacket(const AudioStreamPacket& packet) {
    // Prepare packet header
    struct AudioPacketHeader {
        uint8_t type = 0x01;
        uint8_t flags = 0x00;
        uint16_t payload_len;
        uint32_t ssrc = 0;  // Could use session ID hash or fixed value
        uint32_t timestamp;
        uint32_t sequence;
    } __attribute__((packed));

    // Generate new sequence number
    local_sequence_++;

    // Create header
    AudioPacketHeader header;
    header.payload_len = htons(packet.payload.size());
    header.timestamp = htonl(packet.timestamp);
    header.sequence = htonl(local_sequence_);

    // Encrypt payload
    size_t encrypted_size = packet.payload.size();
    std::vector<uint8_t> encrypted_payload(encrypted_size);
    size_t nc_off = 0;
    uint8_t stream_block[16] = {0};

    // Use existing AES context (aes_ctx_) and nonce (aes_nonce_)
    int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, encrypted_size, &nc_off, 
                                   (uint8_t*)aes_nonce_.data(), stream_block,
                                   (const uint8_t*)packet.payload.data(), 
                                   encrypted_payload.data());

    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to encrypt audio data, ret: %d", ret);
        return "";
    }

    // Serialize complete packet: nonce + header + encrypted_payload
    std::string result;
    result.reserve(aes_nonce_.size() + sizeof(header) + encrypted_size);
    result.append(aes_nonce_);
    result.append(reinterpret_cast<const char*>(&header), sizeof(header));
    result.append(reinterpret_cast<const char*>(encrypted_payload.data()), encrypted_size);

    return result;
}
```

