```cpp
void MqttProtocol::ParseServerHello(const cJSON* root) {
    auto transport = cJSON_GetObjectItem(root, "transport");
    if (transport == nullptr || strcmp(transport->valuestring, "udp") != 0) {
        ESP_LOGE(TAG, "Unsupported transport: %s", transport->valuestring);
        return;
    }

    auto session_id = cJSON_GetObjectItem(root, "session_id");
    if (cJSON_IsString(session_id)) {
        session_id_ = session_id->valuestring;
        ESP_LOGI(TAG, "Session ID: %s", session_id_.c_str());
    }

    auto audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (cJSON_IsObject(audio_params)) {
        auto sample_rate = cJSON_GetObjectItem(audio_params, "sample_rate");
        if (cJSON_IsNumber(sample_rate)) {
            server_sample_rate_ = sample_rate->valueint;
        }
        auto frame_duration = cJSON_GetObjectItem(audio_params, "frame_duration");
        if (cJSON_IsNumber(frame_duration)) {
            server_frame_duration_ = frame_duration->valueint;
        }
    }

    // Handle UDP specific fields
    auto udp_server = cJSON_GetObjectItem(root, "udp_server");
    auto udp_port = cJSON_GetObjectItem(root, "udp_port");
    auto key = cJSON_GetObjectItem(root, "key");

    if (cJSON_IsString(udp_server) && cJSON_IsNumber(udp_port) && cJSON_IsString(key)) {
        udp_server_ = udp_server->valuestring;
        udp_port_ = udp_port->valueint;

        // Decode hex key
        std::string hex_key = key->valuestring;
        aes_key_ = DecodeHexString(hex_key);

        // Initialize AES context
        mbedtls_aes_init(&aes_ctx_);
        mbedtls_aes_setkey_enc(&aes_ctx_, (uint8_t*)aes_key_.data(), aes_key_.size() * 8);

        // Reset sequence numbers
        local_sequence_ = 0;
        remote_sequence_ = 0;

        // Generate random nonce
        aes_nonce_.resize(16);
        for (size_t i = 0; i < aes_nonce_.size(); i++) {
            aes_nonce_[i] = rand() & 0xFF;
        }

        xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
    } else {
        ESP_LOGE(TAG, "Missing required fields in server hello message");
    }
}
```

Key implementation patterns observed:
1. **Transport validation**: Check if the transport type matches expected protocol ("udp" for MQTT vs "websocket" for WebSocket)
2. **Session management**: Extract and store session ID from server response
3. **Audio parameter extraction**: Parse audio configuration parameters (sample rate, frame duration)
4. **Protocol-specific fields**: Handle UDP-specific fields like server address, port, and encryption key
5. **Event signaling**: Use FreeRTOS event groups to signal completion of handshake
6. **Error handling**: Validate all required fields are present before proceeding
7. **AES initialization**: Set up encryption context with received key material
8. **Sequence number management**: Initialize local/remote sequence counters for packet ordering

