{
    size_t payload_size = packet.payload.size();
    size_t total_size = sizeof(BinaryProtocol2) + payload_size;

    std::vector<uint8_t> buffer(total_size);
    BinaryProtocol2* bp2 = reinterpret_cast<BinaryProtocol2*>(buffer.data());

